const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split('\n');
if(input.length===0) process.exit(0);
let T=parseInt(input[0].trim(),10);
let res=[];
for(let i=1;i<=T;i++){
  const s=input[i].trim();
  let upper=0, lower=0;
  for(const ch of s){
    if(ch>='A' && ch<='Z') upper++;
    else if(ch>='a' && ch<='z') lower++;
  }
  res.push(`${upper} ${lower}`);
}
console.log(res.join('\n'));
